contracts/Bridge.sol.content:
// SPDX-License-Identifier: UNLICENSED

pragma solidity 0.8.20;

import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
import {SafeERC20, IERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import {Pausable} from "@openzeppelin/contracts/utils/Pausable.sol";
import {SignatureVerify} from "./signature/SignatureVerify.sol";
import {Errors} from "./Errors.sol";
import { TricornERC20PausableToken } from "./TricornERC20PausableToken.sol";
import {ITokenMessenger} from "./ITokenMessenger.sol";

contract Bridge is SignatureVerify, Ownable, Pausable {
    using SafeERC20 for IERC20;

    /// @notice bridgeIn method parameters
    /// @param token Token address
    /// @param amount Token amount
    /// @param gasCommission Commission which is calculated in transferred token.
    /// @param destinationChain Chain where we transfer tokens
    /// @param destinationAddress Address where we transfer tokens on the chain mentioned above
    /// @param deadline Timestamp until transaction is valid
    /// @param nonce Parameter to avoid repeat transaction attack
    struct BridgeInParams {
        address token;
        uint256 amount;
        uint256 gasCommission;
        string destinationChain;
        string destinationAddress;
        uint256 deadline;
        uint256 nonce;
        uint256 transactionId;
    }

    /// @notice bridgeInCoin method parameters
    /// @param token Token address
    /// @param amount Token amount
    /// @param gasCommission Commission which is calculated in transferred token.
    /// @param destinationChain Chain where we transfer tokens
    /// @param destinationAddress Address where we transfer tokens on the chain mentioned above
    /// @param deadline Timestamp until transaction is valid
    /// @param nonce Parameter to avoid repeat transaction attack
    struct BridgeInCoinParams {
        uint256 gasCommission;
        string destinationChain;
        string destinationAddress;
        uint256 deadline;
        uint256 nonce;
        uint256 transactionId;
    }

    /// @notice bridgeIn method parameters
    /// @param token Token address
    /// @param amount Token amount
    /// @param gasCommission Commission which is calculated in transferred token.
    /// @param destinationChain Chain where we transfer tokens
    /// @param destinationAddress Address where we transfer tokens on the chain mentioned above
    /// @param deadline Timestamp until transaction is valid
    /// @param nonce Parameter to avoid repeat transaction attack
    struct BridgeInParamsCircle {
        address token;
        uint256 amount;
        uint256 gasCommission;
        uint32 destinationChain;
        bytes32 destinationAddress;
        uint256 deadline;
        uint256 nonce;
        uint256 transactionId;
    }

    uint16 private constant _HUNDRED_PERCENT = 10_000;
    uint32 private constant _MAX_STABLE_COMMISSION_PERCENT = 90_00;

    uint32 private _stableCommissionPercent = 4_00;
    address private _circleContract = 0xD0C3da58f55358142b8d3e06C1C30c5C6114EFE8;
    address private _commissionCollector;

    mapping(uint256 => bool) private _usedNonces;
    mapping(address => uint256) private _commissionPools;
    uint256 private _commissionByCoin;

    /// @param sender address who deposit tokens to the bridge
    /// @param nonce classic nonce parameter to track unique transaction
    /// @param token token we deposit to the bridge
    /// @param amount amount of this token
    /// @param stableCommissionPercent Commission percent which is actual on the moment when this event fired.
    /// @param gasCommission Gas commission on the destination chain which is actual when this event fired.
    /// @param destinationChain From what chain we transfer to the recipient
    /// @param destinationAddress From what address(in the above chain) we transfer to the recipient
    event BridgeFundsIn(
        address indexed sender,
        uint256 transactionId,
        uint256 nonce,
        address token,
        uint256 amount,
        uint256 stableCommissionPercent,
        uint256 gasCommission,
        string destinationChain,
        string destinationAddress
    );

    /// @param sender address who deposit coin to the bridge
    /// @param nonce classic nonce parameter to track unique transaction
    /// @param amount amount of coin
    /// @param stableCommissionPercent Commission percent which is actual on the moment when this event fired.
    /// @param gasCommission Gas commission on the destination chain which is actual when this event fired.
    /// @param destinationChain From what chain we transfer to the recipient
    /// @param destinationAddress From what address(in the above chain) we transfer to the recipient
    event BridgeFundsInCoin(
        address indexed sender,
        uint256 transactionId,
        uint256 nonce,
        uint256 amount,
        uint256 stableCommissionPercent,
        uint256 gasCommission,
        string destinationChain,
        string destinationAddress
    );

    /// @param sender address who deposit tokens to the bridge
    /// @param nonce classic nonce parameter to track unique transaction
    /// @param token token we deposit to the bridge
    /// @param amount amount of this token
    /// @param stableCommissionPercent Commission percent which is actual on the moment when this event fired.
    /// @param gasCommission Gas commission on the destination chain which is actual when this event fired.
    /// @param destinationChain From what chain we transfer to the recipient
    /// @param destinationAddress From what address(in the above chain) we transfer to the recipient
    event BridgeFundsInCircle(
        address indexed sender,
        uint256 transactionId,
        uint256 nonce,
        address token,
        uint256 amount,
        uint256 stableCommissionPercent,
        uint256 gasCommission,
        uint32 destinationChain,
        bytes32 destinationAddress
    );

    /// @param sender address who deposit tokens to the bridge and from which address we burn these tokens.
    /// @param nonce classic nonce parameter to track unique transaction
    /// @param token token we deposit to the bridge and burn it
    /// @param amount amount of this token
    /// @param stableCommissionPercent Commission percent which is actual on the moment when this event fired.
    /// @param gasCommission Gas commission on the destination chain which is actual when this event fired.
    /// @param destinationChain From what chain we transfer to the recipient
    /// @param destinationAddress From what address(in the above chain) we transfer to the recipient
    event BridgeFundsInBurn(
        address indexed sender,
        uint256 transactionId,
        uint256 nonce,
        address token,
        uint256 amount,
        uint256 stableCommissionPercent,
        uint256 gasCommission,
        string destinationChain,
        string destinationAddress
    );

    /// @param recipient recepient of the tokens
    /// @param token token we fund out from the bridge
    /// @param amount amount of this token
    /// @param transactionId heper parameter to track
    /// @param sourceChain From what chain we transfer to the recipient
    /// @param sourceAddress From what address(in the chain mentioned above) we transfer to the recipient
    event BridgeFundsOut(
        address indexed recipient,
        address token,
        uint256 amount,
        uint256 transactionId,
        string sourceChain,
        string sourceAddress
    );

    /// @param recipient recepient of the tokens
    /// @param amount amount of coin
    /// @param transactionId heper parameter to track
    /// @param sourceChain From what chain we transfer to the recipient
    /// @param sourceAddress From what address(in the chain mentioned above) we transfer to the recipient
    event BridgeFundsOutCoin(
        address indexed recipient,
        uint256 amount,
        uint256 transactionId,
        string sourceChain,
        string sourceAddress
    );

    /// @param recipient recepient of the tokens on which we mint these tokens.
    /// @param token token we fund out from the bridge
    /// @param amount amount of minted tokens
    /// @param transactionId heper parameter to track
    /// @param sourceChain From what chain we transfer to the recipient
    /// @param sourceAddress From what address(in the chain mentioned above) we transfer to the recipient
    event BridgeFundsOutMint(
        address indexed recipient,
        address token,
        uint256 amount,
        uint256 transactionId,
        string sourceChain,
        string sourceAddress
    );

    /// @param recipient recepient of the tokens (user who transfer his tokens out)
    /// @param nonce classic nonce parameter to track unique transaction
    /// @param token token we fund out from the bridge
    /// @param amount amount of this token
    event TransferOut(
        address indexed recipient,
        uint256 transactionId,
        uint256 nonce,
        address token,
        uint256 amount
    );

    /// @param token token we withdraw from the commission pool
    /// @param amount amount of this token
    event WithdrawCommission(address indexed token, uint256 amount);

    /// @param amount amount of coin
    event WithdrawCoinCommission(uint256 indexed amount);

    /**
     * @dev Throws if called by any account other than the commission collector.
     */
    modifier onlyCommissionCollector() {
        if (_msgSender() != _commissionCollector) {
            revert(Errors.INVALID_COMMISSION_COLLECTOR_ADDRESS);
        }
        _;
    }

    constructor(address signer) SignatureVerify(signer) Ownable(msg.sender) {}

    /// @notice Deposit tokens on the bridge to transfer them onto another chain
    /// @dev Deposit tokens on the bridge to transfer them onto another chain
    function bridgeIn(
        BridgeInParams calldata params,
        bytes calldata signature
    ) external whenNotPaused {

        _bridgeInCommonOperations(params, signature);

        // uint256 balanceBefore = IERC20(params.token).balanceOf(address(this));
        IERC20(params.token).safeTransferFrom(
            _msgSender(),
            address(this),
            params.amount
        );
        //uint256 transferredAmount = params.amount;

        emit BridgeFundsIn(
            _msgSender(),
            params.transactionId,
            params.nonce,
            params.token,
            params.amount,
            _stableCommissionPercent,
            params.gasCommission,
            params.destinationChain,
            params.destinationAddress
        );
    }

    /// @notice Deposit coin on the bridge to transfer them onto another chain
    /// @dev Deposit coin on the bridge to transfer them onto another chain
    function bridgeInCoin(
        BridgeInCoinParams calldata params,
        bytes calldata signature
    ) external payable whenNotPaused {

        _bridgeInCoinCommonOperations(params, signature);

        emit BridgeFundsInCoin(
            _msgSender(),
            params.transactionId,
            params.nonce,
            msg.value,
            _stableCommissionPercent,
            params.gasCommission,
            params.destinationChain,
            params.destinationAddress
        );
    }

    /// @notice Deposit tokens on the bridge to transfer them onto another chain
    /// @dev Deposit tokens on the bridge to transfer them onto another chain
    function bridgeInCircle(
        BridgeInParamsCircle calldata params,
        bytes calldata signature
    ) external whenNotPaused {
        if (params.token == address(0)) {
            revert(Errors.INVALID_TOKEN_ADDRESS);
        }

        if (params.destinationAddress.length == 0) {
            revert(Errors.INVALID_DESTIONATION_ADDRESS);
        }

        if (params.destinationChain > 10) {
            revert(Errors.INVALID_DESTIONATION_CHAIN); // up 10 networks
        }

        uint256 totalCommission = getTotalCommission(params.amount, params.gasCommission);

        if (totalCommission >= params.amount) {
            revert(Errors.COMMISSION_GREATER_THAN_AMOUNT);
        }

        if (_usedNonces[params.nonce]) {
            revert(Errors.ALREADY_USED_SIGNATURE);
        }

        if (block.timestamp > params.deadline) {
            revert(Errors.EXPIRED_SIGNATURE);
        }
        {
            _checkBridgeInRequestCircle(
                _msgSender(),
                address(this),
                params.token,
                params.amount,
                params.gasCommission,
                params.destinationChain,
                params.destinationAddress,
                params.deadline,
                params.nonce,
                params.transactionId,
                getChainId(),
                signature
            );

            _usedNonces[params.nonce] = true;

            _commissionPools[params.token] += totalCommission;
        }

        IERC20(params.token).safeTransferFrom(_msgSender(), address(this), params.amount);

        uint256 amountToBurn = params.amount - totalCommission;

        IERC20(params.token).approve(_circleContract, amountToBurn);

        ITokenMessenger(_circleContract).depositForBurn(
            amountToBurn, 
            params.destinationChain,
            params.destinationAddress,
            params.token
        );


        emit BridgeFundsInCircle(
            _msgSender(),
            params.transactionId,
            params.nonce,
            params.token,
            params.amount,
            _stableCommissionPercent,
            params.gasCommission,
            params.destinationChain,
            params.destinationAddress
        );
    }

    /// @notice Deposit tokens on the bridge to transfer them onto another chain. Burn these tokens to mint them on another chain eventually.
    /// @dev Deposit tokens on the bridge to transfer them onto another chain
    function bridgeInBurn(
        BridgeInParams calldata params,
        bytes calldata signature
    ) external whenNotPaused {
        _bridgeInCommonOperations(params, signature);

        uint256 totalCommission = getTotalCommission(
            params.amount,
            params.gasCommission
        );

        IERC20(params.token).safeTransferFrom(
            _msgSender(),
            address(this),
            totalCommission
        );

        TricornERC20PausableToken(params.token).burn(
            _msgSender(),
            params.amount - totalCommission
        );

        emit BridgeFundsInBurn(
            _msgSender(),
            params.transactionId,
            params.nonce,
            params.token,
            params.amount,
            _stableCommissionPercent,
            params.gasCommission,
            params.destinationChain,
            params.destinationAddress
        );
    }
    /// @notice Withdraw tokens from the bridge. Can be initiated only by the owner
    /// @param token Token address
    /// @param recipient Recipient address
    /// @param amount Token amount
    /// @param transactionId ID of the transaction - helper parameter
    /// @param sourceChain From what chain we transfer to the recipient
    /// @param sourceAddress From what address(in the chain mentioned above) we transfer to the recipient
    function bridgeOut(
        address token,
        address recipient,
        uint256 amount,
        uint256 transactionId,
        string calldata sourceChain,
        string calldata sourceAddress
    ) external onlyOwner {
        _bridgeOutVerify(token, recipient, amount);

        IERC20(token).safeTransfer(recipient, amount);
        emit BridgeFundsOut(
            recipient,
            token,
            amount,
            transactionId,
            sourceChain,
            sourceAddress
        );
    }

    /// @notice Withdraw coin from the bridge. Can be initiated only by the owner
    /// @param recipient Recipient address
    /// @param amount Coin amount
    /// @param transactionId ID of the transaction - helper parameter
    /// @param sourceChain From what chain we transfer to the recipient
    /// @param sourceAddress From what address(in the chain mentioned above) we transfer to the recipient
    function bridgeOutCoin(
        address payable recipient,
        uint256 amount,
        uint256 transactionId,
        string calldata sourceChain,
        string calldata sourceAddress
    ) external onlyOwner {
        _bridgeOutCoinVerify(recipient, amount);

        recipient.transfer(amount);
        emit BridgeFundsOutCoin(
            recipient,
            amount,
            transactionId,
            sourceChain,
            sourceAddress
        );
    }

    /// @notice Withdraw tokens from the bridge - mint them to the address. Can be initiated only by the owner
    /// @param token Token address
    /// @param recipient Recipient address on which we mint tokens
    /// @param amount Token amount
    /// @param transactionId ID of the transaction - helper parameter
    /// @param sourceChain From what chain we transfer to the recipient
    /// @param sourceAddress From what address(in the chain mentioned above) we transfer to the recipient
    function bridgeOutMint(
        address token,
        address recipient,
        uint256 amount,
        uint256 transactionId,
        string calldata sourceChain,
        string calldata sourceAddress
    ) external onlyOwner {
        if (recipient == address(0)) {
            revert(Errors.INVALID_RECIPIENT_ADDRESS);
        }

        if (token == address(0)) {
            revert(Errors.INVALID_TOKEN_ADDRESS);
        }

        TricornERC20PausableToken(token).mint(recipient, amount);
        emit BridgeFundsOutMint(
            recipient,
            token,
            amount,
            transactionId,
            sourceChain,
            sourceAddress
        );
    }

    /// @notice Withdraw commission from the collected pool by the specified token.
    /// This way we do not affect user deposits as long as commission pool collected separately
    /// @param token Token address
    /// @param amount Token amount
    function withdrawCommission(
        address token,
        uint256 amount
    ) external onlyCommissionCollector {
        if (_commissionPools[token] < amount) {
            revert(Errors.AMOUNT_EXCEED_COMMISSION_POOL);
        }
        _commissionPools[token] -= amount;
        IERC20(token).safeTransfer(msg.sender, amount);
        emit WithdrawCommission(token, amount);
    }

    /// @notice Withdraw coin commission from the collected pool by the specified token.
    /// This way we do not affect user deposits as long as commission pool collected separately
    /// @param amount Coin amount
    function withdrawCoinCommission(
        uint256 amount
    ) external onlyCommissionCollector {
        if (_commissionByCoin < amount) {
            revert(Errors.AMOUNT_EXCEED_COMMISSION_POOL);
        }
        _commissionByCoin -= amount;
        payable(msg.sender).transfer(amount);
        emit WithdrawCoinCommission(amount);
    }

    /// @notice Allow user to withdraw tokens back if the backend approved it by providing signature
    /// @param token Token address
    /// @param recipient Recipient address
    /// @param amount Token amount we should return back to the user
    /// @param commission Amount of commission we should return back to the user
    /// @param nonce Parameter to avoid double transaction attack
    /// @param signature Classic signature
    function transferOut(
        address token,
        address recipient,
        uint256 amount,
        uint256 commission,
        uint256 deadline,
        uint256 nonce,
        uint256 transactionId,
        bytes calldata signature
    ) external whenNotPaused {
        if (_usedNonces[nonce]) {
            revert(Errors.ALREADY_USED_SIGNATURE);
        }

        if (block.timestamp > deadline) {
            revert(Errors.EXPIRED_SIGNATURE);
        }

        if (token == address(0)) {
            revert(Errors.INVALID_TOKEN_ADDRESS);
        }

        if (recipient == address(0)) {
            revert(Errors.INVALID_RECIPIENT_ADDRESS);
        }

        _checkTransferOutRequest(
            address(this),
            token,
            recipient,
            amount,
            commission,
            deadline,
            nonce,
            transactionId,
            getChainId(),
            signature
        );

        _usedNonces[nonce] = true;
        _commissionPools[token] -= commission;

        uint256 totalSumForTransfer = amount + commission;
        IERC20(token).safeTransfer(recipient, totalSumForTransfer);

        // TODO:Descrease pool commission
        emit TransferOut(
            recipient,
            transactionId,
            nonce,
            token,
            totalSumForTransfer
        );
    }

    /// @notice Set stable commission percent which is used to calculate static commission Allowed only for onwer
    /// @param stableCommissionPercent_ percent
    function setStableCommissionPercent(
        uint32 stableCommissionPercent_
    ) external onlyOwner {
        if (stableCommissionPercent_ > _MAX_STABLE_COMMISSION_PERCENT) {
            revert(Errors.INVALID_STABLE_COMMISSION_PERCENT);
        }
        _stableCommissionPercent = stableCommissionPercent_;
    }

    /// @notice Set circle contract address
    /// @param circleContract_ contract address
    function setCircleContract(
        address circleContract_
    ) external onlyOwner {
        if (circleContract_ == address(0)) {
            revert(Errors.INVALID_CIRCLE_CONTRACT_ADDRESS);
        }
        _circleContract = circleContract_;
    }

    /// @notice Set commission collector address
    /// @param commissionCollector_ address
    function setCommissionCollector(
        address commissionCollector_
    ) external onlyOwner {
        if (commissionCollector_ == address(0)) {
            revert(Errors.INVALID_COMMISSION_COLLECTOR_ADDRESS);
        }
        _commissionCollector = commissionCollector_;
    }

    /// @notice Stop all contract functionality allowed to the user
    function pause() external onlyOwner {
        _pause();
    }

    /// @notice Resume all contract functionality allowed to the user
    function unpause() external onlyOwner {
        _unpause();
    }

    /// @notice Get stable commission percent which is used to calculate static commission
    /// @return stable commission percent
    function getStableCommissionPercent() external view returns (uint256) {
        return _stableCommissionPercent;
    }

    /// @notice Get circle contract address
    /// @return circle contract address
    function getCirecleContract() external view returns (address) {
        return _circleContract;
    }

    /// @notice Get commission collector address
    /// @return commission collector address
    function getCommissionCollector() external view returns (address) {
        return _commissionCollector;
    }

    /// @notice Get commission collector address
    /// @return commission collector address
    function getCommissionByCoin() external view returns (uint256) {
        return _commissionByCoin;
    }

    /// @notice Get amount of collected commission by the specified token.
    /// @param token Specified token
    /// @return amount of collected commission
    function getCommissionPoolAmount(
        address token
    ) external view onlyOwner returns (uint256) {
        return _commissionPools[token];
    }

    /// @notice Block renounce ownership functionality
    function renounceOwnership() public view override onlyOwner {
        revert(Errors.INVALID_SIGNER_ADDRESS);
    }

    /// @notice Claculate total commission: stable commission percent + gasCommission
    /// @param amount Token amount
    /// @param gasCommission Manual gasCommission
    /// @return total commission user should pay for transfer
    function getTotalCommission(
        uint256 amount,
        uint256 gasCommission
    ) public view returns (uint256) {
        uint256 stableCommission = (amount * _stableCommissionPercent) /
            _HUNDRED_PERCENT;
        uint256 totalCommission = stableCommission + gasCommission;
        return totalCommission;
    }

    function getChainId() public view returns (uint256) {
        uint256 id;
        assembly {
            id := chainid()
        }
        return id;
    }

    function getContractBalance() external view returns (uint256) {
        return address(this).balance;
    }

    function _bridgeInCommonOperations(
        BridgeInParams calldata params,
        bytes calldata signature
    ) private {

        if (params.token == address(0)) {
            revert(Errors.INVALID_TOKEN_ADDRESS);
        }

        if (bytes(params.destinationAddress).length == 0) {
            revert(Errors.INVALID_DESTIONATION_ADDRESS);
        }

        if (bytes(params.destinationChain).length == 0) {
            revert(Errors.INVALID_DESTIONATION_CHAIN);
        }

        uint256 totalCommission = getTotalCommission(
            params.amount,
            params.gasCommission
        );

        if (totalCommission >= params.amount) {
            revert(Errors.COMMISSION_GREATER_THAN_AMOUNT);
        }

        if (_usedNonces[params.nonce]) {
            revert(Errors.ALREADY_USED_SIGNATURE);
        }

        if (block.timestamp > params.deadline) {
            revert(Errors.EXPIRED_SIGNATURE);
        }
        {
            _checkBridgeInRequest(
                _msgSender(),
                address(this),
                params.token,
                params.amount,
                params.gasCommission,
                params.destinationChain,
                params.destinationAddress,
                params.deadline,
                params.nonce,
                params.transactionId,
                getChainId(),
                signature
            );

            _usedNonces[params.nonce] = true;

            _commissionPools[params.token] += totalCommission;
        }
    }

    function _bridgeInCoinCommonOperations(
        BridgeInCoinParams calldata params,
        bytes calldata signature
    ) private {
        if (bytes(params.destinationAddress).length == 0) {
            revert(Errors.INVALID_DESTIONATION_ADDRESS);
        }

        if (bytes(params.destinationChain).length == 0) {
            revert(Errors.INVALID_DESTIONATION_CHAIN);
        }

        uint256 totalCommission = getTotalCommission(
            msg.value,
            params.gasCommission
        );

        if (totalCommission >= msg.value) {
            revert(Errors.COMMISSION_GREATER_THAN_AMOUNT);
        }

        if (_usedNonces[params.nonce]) {
            revert(Errors.ALREADY_USED_SIGNATURE);
        }

        if (block.timestamp > params.deadline) {
            revert(Errors.EXPIRED_SIGNATURE);
        }
        {
            _checkBridgeInCoinRequest(
                _msgSender(),
                address(this),
                params.gasCommission,
                params.destinationChain,
                params.destinationAddress,
                params.deadline,
                params.nonce,
                params.transactionId,
                getChainId(),
                signature
            );

            _usedNonces[params.nonce] = true;

            _commissionByCoin += totalCommission;
        }
    }


    function _bridgeOutVerify(
        address token,
        address recipient,
        uint256 amount
    ) private view {
        if (recipient == address(0)) {
            revert(Errors.INVALID_RECIPIENT_ADDRESS);
        }

        if (token == address(0)) {
            revert(Errors.INVALID_TOKEN_ADDRESS);
        }
        uint256 balance = IERC20(token).balanceOf(address(this));
        uint256 allowedBalance = balance - _commissionPools[token];
        if (amount > allowedBalance) {
            revert(Errors.AMOUNT_EXCEED_BRIDGE_POOL);
        }
    }

    function _bridgeOutCoinVerify(
        address recipient,
        uint256 amount
    ) private view {
        if (recipient == address(0)) {
            revert(Errors.INVALID_RECIPIENT_ADDRESS);
        }

        uint256 balance = address(this).balance;
        uint256 allowedBalance = balance - _commissionByCoin;
        if (amount > allowedBalance) {
            revert(Errors.AMOUNT_EXCEED_BRIDGE_POOL);
        }
    }
}

